namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Exception
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.CreatedAt).ToListAsync();
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(
            s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = GenerateTrackingNumber();
        shipment.CreatedAt = DateTime.UtcNow;
        shipment.Status = ShipmentStatus.Pending;
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

