                        <dt>Description</dt>
                        <dd>@(string.IsNullOrWhiteSpace(shipment.Description) ? "—" : shipment.Description)</dd>
                        <dt>Shipped On</dt>
                        <dd>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

