@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-success w-100" @onclick="ShowCreateForm">
            + New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">Create Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Origin"
                           @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Destination"
                           @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input type="email" class="form-control" placeholder="Customer Email"
                           @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Description"
                           @bind="newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control"
                           @bind="estimatedDeliveryDate" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-1" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm d-inline-block w-auto"
                                value="@shipment.Status"
                                @onchange="(e) => ChangeStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;
    private bool showCreateForm;
    private Shipment newShipment = new();
    private DateTime? estimatedDeliveryDate;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrWhiteSpace(filterText) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrWhiteSpace(filterStatus) ||
             s.Status.ToString() == filterStatus));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new Shipment();
        estimatedDeliveryDate = null;
    }

    private async Task CreateShipment()
    {
        newShipment.EstimatedDelivery = estimatedDeliveryDate.HasValue
            ? DateTime.SpecifyKind(estimatedDeliveryDate.Value, DateTimeKind.Utc)
            : null;
        await ShipmentService.CreateShipmentAsync(newShipment);
        showCreateForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task ChangeStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
