                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <span class="fs-5 fw-bold text-primary">
                                    @shipment.EstimatedDelivery.Value.ToString("dddd, MMMM dd, yyyy")
                                </span>
                            }
                            else
                            {
                                <span class="text-muted">Not yet determined</span>
                            }
