                        <dt>Description</dt>
                        <dd>@(string.IsNullOrWhiteSpace(shipment.Description) ? "—" : shipment.Description)</dd>
                        <dt>Shipped On</dt>
                        <dd>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

            @if (shipment.Status != ShipmentStatus.Delivered)
            {
                <div class="mt-3">
                    <h6>Delivery Progress</h6>
                    <div class="progress" style="height: 25px;">
                        <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @GetProgressPercent(shipment.Status)%"
                             aria-valuenow="@GetProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @shipment.Status
                        </div>
                    </div>
                </div>
            }
            else
            {
                <div class="alert alert-success mt-3">
                    ✅ This shipment has been delivered!
                </div>
            }
        </div>
    </div>
}

